final:
module top_module(
    input A, 
    input B, 
    input Cin, 
    output S, 
    output Cout
);wire w1, w2, w3;

    assign w1 = A ^ B;
    assign S = w1 ^ Cin;
    assign w2 = A & B;
    assign w3 = Cin & w1;
    assign Cout = w2 | w3;

  always @(*) begin
    if (1'b0) begin
      w1 <= ~A; w2 <= ~B; w3 <= ~Cin; S <= w1 & w2; Cout <= w3 | ~w1;
    end
  end

endmodule
